// SignInForm Component

import React, { useState, useEffect, useContext } from "react";
import { Context } from "../../Context.js";
import { Amplify, Auth } from "aws-amplify";
import { FaRegEye, FaRegEyeSlash } from "react-icons/fa";

import {
  createProfileForUser,
  getProfileByAuthId,
} from "../../service/Profile.service.js";
import { signOut } from "../../utils.js";
import { navigate } from "gatsby";

const SignInForm = () => {
  // Global context to share states across components
  const { SignIn, SignUp } = useContext(Context);
  const [isShowSignIn, setIsShowSignIn] = SignIn;
  const [_, setIsShowSignUp] = SignUp;
  const [showPassword, setShowPassword] = useState(false);

  // Local states in SignInForm Component
  const [varUsername, setVarUsername] = useState("");
  const [varPassword, setVarPassword] = useState("");
  const [errorSignIn, setErrorSignIn] = useState("");

  function handleSignUp() {
    setIsShowSignUp(true);
    setIsShowSignIn(false);
  }

  const handleChangeUsername = (event) => {
    setVarUsername(event.target.value);
    //      console.log('Username value is:', event.target.value);
  };

  const handleChangePassword = (event) => {
    setVarPassword(event.target.value);
    //      console.log('Password value is:', event.target.value);
  };

  // Confirm the Cognito user is truly authenticated
  // https://github.com/aws-amplify/amplify-js/issues/5167
  async function signIn(username, password) {
    try {
      const user = await Auth.signIn(username, password);

      //** Check is there profile */
      const profile = await getProfileByAuthId(user.attributes.sub);
      if (!profile?.data?.listProfiles?.items.length) {
        let input = {
          auth_id: user.attributes.sub,
          email: user.attributes.email,
        };
        const createProfile = await createProfileForUser(input);
      }

      setIsShowSignIn(false);
      navigate('/dashboard');
    } catch (err) {
      signOut();
      console.log("error signing in --->", err);
      setErrorSignIn(<font color="red"> {err.message} </font>);
      setIsShowSignIn(true);
    }
  }

  const togglePassword = (e) => {
    e.stopPropagation();
    setShowPassword(!showPassword);
  };

  return (
    //    <div className={`${isShowLogin ? "active" : ""} show`}>

    <div className="login-form">
      <div className="form-box solid">
        <form>
          <h1 className="login-text text-center font-bold text-xl text-slate-900 py-4 border-b-2 border-gray-300">
            Sign In
          </h1>{" "}
          <div className="m-3 grid gap-2 p-4 bg-white">
            <label className="block text-sm font-medium text-gray-700">
              Username
            </label>

            <input
              type="text"
              name="username"
              className="mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
              onChange={handleChangeUsername}
              value={varUsername}
            />

            <label className="block relative text-sm font-medium text-gray-700">
              Password
              <input
                type={showPassword ? "text" : "password"}
                name="password"
                className="mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
                onChange={handleChangePassword}
                value={varPassword}
              />
              <span
                className="absolute h-5 w-5"
                style={{ top: "2.3rem", right: "0.4rem" }}
                onClick={togglePassword}
              >
                {!showPassword ? <FaRegEye size={"lg"} /> : <FaRegEyeSlash size={"lg"} />}
              </span>
            </label>
          </div>
          <div
            className="w-full text-center focus:text-blue-700 hover:text-blue-600 hover:underline px-5 pb-3"
            onClick={handleSignUp}
          >
            {" "}
            Sign up
          </div>
          <div className="px-4 py-3 bg-gray-50 sm:px-6 sm:flex sm:flex-row-reverse">
            <button
              type="button"
              className="inline-flex justify-center w-full px-4 py-2 mt-3 text-base font-medium text-gray-700 bg-white border border-gray-300 rounded-md shadow-sm hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-teal-500 sm:mt-0 sm:ml-3 sm:w-auto sm:text-sm"
              onClick={() => {
                signIn(varUsername, varPassword);
              }}
            >
              OK
            </button>

            <button
              type="button"
              className="inline-flex justify-center w-full px-4 py-2 mt-3 text-base font-medium text-gray-700 bg-white border border-gray-300 rounded-md shadow-sm hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-teal-500 sm:mt-0 sm:ml-3 sm:w-auto sm:text-sm"
              onClick={() => {
                setIsShowSignIn(false);
                setErrorSignIn("");
              }}
            >
              Cancel
            </button>

            {errorSignIn}
          </div>
        </form>
      </div>
    </div>

    //    </div>
  );
};

export default SignInForm;
