import { Link } from "gatsby";
import { Heart, LogOut, Settings, UserRound } from "lucide-react";
import React from "react";
import  { navigate} from "gatsby"

const DropDown = (props) => {
  function handleLogout(){
    props.signOut();
    props.setAvatarState(prev=> !prev);
    navigate("/");
  }
  return ( 
     <div className="w-80 p-6 right-0 rounded-lg absolute text-gray-900 shadow-lg bg-white">
        <Link to="/profile" >
          <section className="flex items-center gap-3 p-3 rounded-md hover:bg-slate-600 transition duration-300 cursor-pointer">
            <span className="text-xl">
              <UserRound />
            </span>
            <span className="text-lg font-medium">Profile</span>
          </section>
        </Link>

      <section className="flex items-center gap-3 p-3 rounded-md hover:bg-slate-600 transition duration-300 cursor-pointer">
        <span className="text-xl">
          <Heart />
        </span>
        <span className="text-lg font-medium">Favorite</span>
      </section>

      <section className="flex items-center gap-3 p-3 rounded-md hover:bg-slate-600 transition duration-300 cursor-pointer">
        <span className="text-xl">
          <Settings />
        </span>
        <span className="text-lg font-medium">Settings</span>
      </section>

      <section onClick={handleLogout} className="flex items-center gap-3 p-3 rounded-md hover:bg-red-400 transition duration-300 cursor-pointer">
        <span className="text-xl">
          <LogOut />
        </span>
        <span className="text-lg font-medium">Logout</span>
      </section>

      <div className="mt-6 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <label className="relative inline-flex items-center cursor-pointer">
            <input type="checkbox" className="sr-only peer" />
            <div className="w-10 h-5 bg-gray-600 peer-focus:ring-4 peer-focus:ring-blue-300 rounded-full peer-checked:bg-blue-500"></div>
          </label>
          <span className="text-lg font-medium">Night Mode</span>
        </div>
      </div>
    </div>
  );
};

export default DropDown;




