// NavBar Component

import React, { useState, useEffect, useContext, useRef } from 'react'
import { Link, graphql, StaticQuery } from 'gatsby'
// import { ReactComponent as Logo } from '/public/img/logo.svg'
import handleClick from '../../handleClick.js'
import LogoSvg from '../../assets/img/logo.svg'

import {cookieName, setCookie} from '../../cookies'
import SignInForm from '../SignInForm/index.js'
import SignUpForm from '../SignUpForm/index.js'

// Utility functions shared across components
import {signOut} from '../../utils.js'
import { Context } from "../../Context.js";


import { OutboundLink } from "gatsby-plugin-google-gtag"

import useAuth from '../useAuth'
import { Amplify, Auth, Hub } from 'aws-amplify';
import awsconfig from '../../aws-exports';

import ReactAvatar from 'react-avatar'
import DropDown from '../AvatarDropDownTemplate/dropDown.js'
import { Img } from '@chakra-ui/react'
Amplify.configure(awsconfig);


// Setup AWS confirm code callback after sign up
// https://github.com/aws-amplify/amplify-js/issues/7555
const getCurrentUser = async (data) => {
  console.log('listening to events', data)
};

Hub.listen('auth', (data) => {
  switch (data.payload.event) {
    case 'signIn':
      // we can set cookies here
      const cookieData = data.payload.data.attributes;
      setCookie(cookieName, {...cookieData, username: data.payload.data.username});
      // routeChange('/dashboard');
      break;

    case 'autoSignIn':
      console.log('autoSignIn', data);
      //        localStorage.setItem("authenticated", true);
      // routeChange('/dashboard');
      window.lintrk('track', { conversion_id: 12804444 }); // LandingPageSignUpSuccess
      break;
    case 'cognitoHostedUI':
      getCurrentUser(data);
      break;
    case 'signIn_failure':
    case 'cognitoHostedUI_failure':
      console.log('Sign in failure', data);
      break;
    default:
      break;
  }
});



const NavBar = ({ toggleNavbar, isActive, appLive }) => {

const [loginVisible, setLoginVisible ] = useState(false)
//const [isShowSignIn, setIsShowSignIn] = useState(false);
//const [isShowSignUp, setIsShowSignUp] = useState(false);

const { SignIn, SignUp } = useContext(Context);
const [ isShowSignIn, setIsShowSignIn ] = SignIn;
const [ isShowSignUp, setIsShowSignUp ] = SignUp;




const [error, setError] = useState('')

// https://bobbyhadz.com/blog/react-get-input-value
// Input fields must be read

// Check if the user is logged in or not using useAuth hook
// https://github.com/aws-amplify/amplify-js/issues/3640#issuecomment-511137854
const { currentUser } = useAuth();
const [avatarState, setAvatarState] = useState(Boolean(currentUser?.username));
const toggleAvatar = ()=> setAvatarState(prev=>!prev);

  // const toggleLoginVisible = () => setLoginVisible(!loginVisible)

  return (
    <StaticQuery
      query={graphql`
        query SearchIndexQuery {
          siteSearchIndex {
            index
          }
        }
      `}
      render={(data) => (
        <>
          <nav className="z-50 flex flex-wrap items-center justify-between p-6 text-black bg-white border-b">
            <div className="flex items-center flex-shrink-0 text-white">
              {/* <Logo
                className="w-auto fill-current"
                viewBox="0 0 84.552 84.552"
              /> */}
              <Link to='/'>
                <img src={LogoSvg}/>
              </Link>
            </div>
            <div className="block lg:hidden" onClick={toggleNavbar}>
              <button className="flex items-center px-3 py-2 text-teal-200 border border-teal-400 rounded hover:text-white hover:border-white">
                <svg
                  className="w-3 h-3 fill-current"
                  viewBox="0 0 20 20"
                  xmlns="http://www.w3.org/2000/svg"
                >
                  <title>Menu</title>
                  <path d="M0 3h20v2H0V3zm0 6h20v2H0V9zm0 6h20v2H0v-2z" />
                </svg>
              </button>
            </div>
            <div
              className={
                (isActive ? "" : "hidden") +
                " ms-auto block w-full text-black lg:flex lg:items-center lg:w-auto gap-8"
              }
            >
              <div className="text-base flex gap-8">
                <Link
                  to="/"
                  className="block lg:inline-block hover:text-black text-base uppercase font-medium"
                >
                  Home
                </Link>
                {currentUser !== null ? (
                  <a
                    href="https://jointutti.com/dashboard"
                    className="block lg:inline-block hover:text-black uppercase font-medium"
                  >
                    Dashboard
                  </a>
                ) : null}
                <Link
                  to="/"
                  className="block lg:inline-block hover:text-black uppercase font-medium"
                >
                  How it works
                </Link>
                {/* <Link
                  to="/about"
                  className="block lg:inline-block hover:text-black uppercase font-medium"
                >
                  About
                </Link>
                <Link
                  to="/blog"
                  className="block lg:inline-block hover:text-black uppercase font-medium"
                >
                  Blog
                </Link> */}
                <Link
                  to="/"
                  className="block lg:inline-block hover:text-black uppercase font-medium"
                >
                  Faq
                </Link>
                <Link
                  to="/"
                  className="block lg:inline-block hover:text-black uppercase font-medium"
                >
                  Contact
                </Link>
              </div>
              <div>
                {/*<a href='https://generate.jointutti.com' className='flex-grow inline-block px-8 py-2 my-4 mr-4 text-sm text-white border border-teal-500 rounded sm:my-0 hover:bg-teal-700 hover:border-teal-700'>
                  Create Tags Now
                </a>*/}

                {/* Order Printed Tags */}
                {/*<button onClick={() => {
                 setLoginVisible(true);
                 handleClick("OrderTagNavBar");
                 }}
                 className='flex-grow px-8 py-2 my-4 mr-5  text-sm text-white bg-teal-500 border border-teal-500 rounded sm:my-0 hover:bg-teal-700 hover:border-teal-700'>
                 Order Printed Tags
                 </button> */}

                {/* Sign Up */}
                {/*{(currentUser  === null) ? (<button onClick={() => {  */}
                {/*       setIsShowSignUp((isShowSignUp) => !isShowSignUp);  */}
                {/*       console.log("isShowSignUp:", isShowSignUp);  */}
                {/*       handleClick("SignUp");  */}
                {/*       window.lintrk('SignUp', { conversion_id: 12784580 }); // LinkedIn Ads  */}
                {/*   }}  */}
                {/*    className='flex-grow px-8 py-2 my-4  mr-5 text-sm text-white bg-teal-500 border border-teal-500 rounded sm:my-0 hover:bg-teal-700 hover:border-teal-700'>  */}
                {/* Sign Up  */}
                {/*    </button>) : null  */}
                {/* }  */}

                {/* Sign In */}
                {currentUser === null ? (
                  <button
                    onClick={() => {
                      if(!isShowSignUp)
                        setIsShowSignIn((isShowSignIn) => !isShowSignIn);
                      handleClick("Sign In");
                    }}
                    className="flex-grow px-8 py-2 my-4 text-base text-white theme-second-color-bg rounded sm:my-0"
                  >
                    Sign In
                  </button>
                ) : null}
              {/* <ReactAvatar size='40' round name={currentUser?.username|| "Noobie learner  "} onClick = {toggleAvatar} className='cursor-pointer' /> */}


                {/* Sign Out */}
                {currentUser !== null ? (
                  <div>
                    {/* Hello {currentUser.username} */}
                    <ReactAvatar size="40" round name={currentUser.username} onClick = {toggleAvatar} className='cursor-pointer' />
                    {/* <div>
                      <button
                        className="no-underline hover:underline"
                        onClick={() => {
                          signOut();
                        }}
                      >
                        Sign Out
                      </button>
                    </div> */}
                  </div>
                ) : null}
                {avatarState && <DropDown setAvatarState={setAvatarState} signOut={signOut}/>}

                {/* Download App */}
                {/* <a href='' className='inline-block px-4 py-2 mt-4 text-sm leading-none text-white border border-white rounded hover:border-transparent hover:text-teal-500 hover:bg-white lg:mt-0'>Download</a> */}
              </div>
            </div>
          </nav>

          {/* Pop Up For Sign Up  */}
          {isShowSignUp ? <SignUpForm /> : null}

          {/* Pop Up For Sign In  */}
          {isShowSignIn ? (
            <div className="fixed inset-0 z-10 overflow-y-auto">
              <div className="flex items-end justify-center min-h-screen px-4 pt-4 pb-20 text-center sm:block sm:p-0">
                <div
                  className="fixed inset-0 transition-opacity"
                  aria-hidden="true"
                >
                  <div className="absolute inset-0 bg-gray-500 opacity-75" />
                </div>

                {/* }<!-- This element is to trick the browser into centering the modal contents. --> */}
                <span
                  className="hidden sm:inline-block sm:align-middle sm:h-screen"
                  aria-hidden="true"
                >
                  &#8203;
                </span>

                <div
                  className="inline-block overflow-hidden text-left align-bottom bg-white rounded-lg shadow-xl transform transition-all sm:my-8 sm:align-middle sm:max-w-lg sm:w-full"
                  role="dialog"
                  aria-modal="true"
                  aria-labelledby="modal-headline"
                >
                  <SignInForm />
                </div>
              </div>
            </div>
          ) : null}

          {loginVisible ? (
            <div className="fixed inset-0 z-10 overflow-y-auto">
              <div className="flex items-end justify-center min-h-screen px-4 pt-4 pb-20 text-center sm:block sm:p-0">
                {/* <!--
      Background overlay, show/hide based on modal state.

      Entering: "ease-out duration-300"
        From: "opacity-0"
        To: "opacity-100"
      Leaving: "ease-in duration-200"
        From: "opacity-100"
        To: "opacity-0"
          --> */}
                <div
                  className="fixed inset-0 transition-opacity"
                  aria-hidden="true"
                >
                  <div className="absolute inset-0 bg-gray-500 opacity-75" />
                </div>

                {/* }<!-- This element is to trick the browser into centering the modal contents. --> */}
                <span
                  className="hidden sm:inline-block sm:align-middle sm:h-screen"
                  aria-hidden="true"
                >
                  &#8203;
                </span>
                {/* <!--
      Modal panel, show/hide based on modal state.

      Entering: "ease-out duration-300"
        From: "opacity-0 translate-y-4 sm:translate-y-0 sm:scale-95"
        To: "opacity-100 translate-y-0 sm:scale-100"
      Leaving: "ease-in duration-200"
        From: "opacity-100 translate-y-0 sm:scale-100"
        To: "opacity-0 translate-y-4 sm:translate-y-0 sm:scale-95"
      --> */}
                <div
                  className="inline-block overflow-hidden text-left align-bottom bg-white rounded-lg shadow-xl transform transition-all sm:my-8 sm:align-middle sm:max-w-lg sm:w-full"
                  role="dialog"
                  aria-modal="true"
                  aria-labelledby="modal-headline"
                >
                  <div className="px-4 pt-5 pb-4 bg-white sm:p-6 sm:pb-4">
                    <div className="sm:flex sm:items-start">
                      <div className="flex items-center justify-center flex-shrink-0 w-12 h-12 mx-auto bg-red-100 rounded-full sm:mx-0 sm:h-10 sm:w-10">
                        {/* <!-- Heroicon name: exclamation --> */}
                        <svg
                          className="w-6 h-6 text-teal-400"
                          xmlns="http://www.w3.org/2000/svg"
                          fill="none"
                          viewBox="0 0 24 24"
                          stroke="currentColor"
                          aria-hidden="true"
                        >
                          <path
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            strokeWidth="2"
                            d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"
                          />
                        </svg>
                      </div>
                      <div className="mt-3 text-center sm:mt-0 sm:ml-4 sm:text-left">
                        <h3
                          className="text-lg font-medium text-gray-900 leading-6"
                          id="modal-headline"
                        >
                          {/* <!--Download Code --> */}
                          Order Printed Tags
                        </h3>

                        <div className="mt-2">
                          <p className="text-sm text-gray-500">
                            If you want to order tags that are ready to
                            authenticate, contact hello@jointutti.com.
                          </p>

                          {/* <!--<p className='text-sm text-gray-500'>
                            Please input your download code. If you do not have one, please reach out to hello@blocktag.com for more details.
                          </p>
                    
                          <input className='w-full p-4 mt-4 border border-gray-300 focus:ring-indigo-500 focus:border-indigo-500 rounded-md' placeholder='Code' onChange={() => setError('')} />
                          <p className='mt-2 text-sm text-red-600'>{error}</p>
                    --> */}
                        </div>
                      </div>
                    </div>
                  </div>

                  <div className="px-4 py-3 bg-gray-50 sm:px-6 sm:flex sm:flex-row-reverse">
                    {/*
                    <button type='button' className='inline-flex justify-center w-full px-4 py-2 text-base font-medium text-white bg-teal-600 border border-transparent rounded-md shadow-sm hover:bg-teal-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-teal-500 sm:ml-3 sm:w-auto sm:text-sm' onClick={() => setError('Invalid code')}>
                      Download
                    </button>
              */}

                    <button
                      type="button"
                      className="inline-flex justify-center w-full px-4 py-2 mt-3 text-base font-medium text-gray-700 bg-white border border-gray-300 rounded-md shadow-sm hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-teal-500 sm:mt-0 sm:ml-3 sm:w-auto sm:text-sm"
                      onClick={() => {
                        setLoginVisible(false);
                        setError("");
                      }}
                    >
                      OK
                    </button>
                  </div>
                </div>
              </div>
            </div>
          ) : null}
        </>
      )}
    />
  );
}

export default NavBar
